{"file_path":"/project/kotlinx-coroutines-core/jvm/test/flow/TimeoutBugTest.kt","content":"package kotlinx.coroutines.flow

import kotlinx.coroutines.testing.*
import kotlinx.coroutines.*
import kotlinx.coroutines.channels.*
import org.junit.Test
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

class TimeoutBugTest : TestBase() {

    @Test
    fun testCallbackFlowTimeoutException() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        try {
            flow.collect()
            fail("Should have thrown IllegalStateException")
        } catch (e: IllegalStateException) {
            assertEquals("Test Exception", e.message)
        }
    }

    @Test
    fun testCallbackFlowWithCatchTimeoutException() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.catch { throw it }.timeout(5.seconds)

        try {
            flow.collect()
            fail("Should have thrown IllegalStateException")
        } catch (e: IllegalStateException) {
            assertEquals("Test Exception", e.message)
        }
    }
}
"}

